INSERT INTO `categories` VALUES (1,'Belgian Ale','belgian-ale','Famiglia di birre ad alta fermentazione caratterizzate da esteri fruttati, fenoli speziati e profili aromatici complessi derivati dal lievito.'),(2,'English Ale','english-ale','Birra ad alta fermentazione con equilibrio tra malto e luppolo, corpo medio e profilo aromatico dominato da note maltate e fruttate.'),(3,'Porter','porter','Birra scura ad alta fermentazione con utilizzo di malti tostati che conferiscono aromi di cacao, caffè e pane tostato.'),(4,'IPA','ipa','Stile ad alta fermentazione caratterizzato da una marcata luppolatura, elevata intensità aromatica e amaro generalmente sostenuto.'),(5,'Lambic','lambic','Birra a fermentazione spontanea ottenuta tramite l\'azione di lieviti e batteri selvaggi, con spiccata acidità e grande complessità.'),(6,'Stout','stout','Birra scura ad alta fermentazione prodotta con malti e orzi tostati, dal profilo ricco e persistente con note torrefatte.'),(7,'Weiss','weiss','Birra di frumento ad alta fermentazione, caratterizzata da elevata carbonazione e aromi di banana e spezie prodotti dal lievito.'),(8,'Analcolica','analcolica','Birra con titolo alcolometrico non superiore all\'1,2% vol.'),(9,'Lager','lager','Birra a bassa fermentazione maturata a freddo, caratterizzata da profilo pulito, elevata bevibilità e buona attenuazione.'),(10,'Barley Wine','barley-wine','Birra ad alta gradazione alcolica, ricca di malto, con struttura importante e note evolutive che aumentano con l\'invecchiamento.'),(11,'Grape Ale','grape-ale','Stile che integra mosto o uva alla produzione brassicola, combinando caratteristiche fermentative del vino e della birra.'),(12,'Blanche','blanche','Birra di frumento ad alta fermentazione, generalmente speziata con coriandolo e scorza d\'agrumi, dal profilo fresco e leggermente velato.'),(13,'Gluten Free','gluten-free','Birra con certificazione Gluten Free'),(14,'Sour','sour','Birra caratterizzata da una spiccata acidità, ottenuta tramite fermentazioni con lieviti e batteri selezionati o tecniche di acidificazione controllata. Presenta aromi freschi, complessi e spesso fruttati.');
/*!40000 ALTER TABLE `categories` ENABLE KEYS */;
UNLOCK TABLES;

