INSERT INTO `products` VALUES (1,'Elisir Dorato','Blonde Ale dal colore dorato brillante con schiuma compatta e persistente. Aromi floreali e mielati accompagnano una bevuta equilibrata e scorrevole, con amaro delicato e finale pulito.','Una birra luminosa e facile da bere, con note di miele, cereali e fiori di campo.','Italia','L\'Alchimista del Luppolo',5.20,'elisir-dorato.webp','6-8°C',2.75,'elisir-dorato','2026-06-22 10:04:58','2026-06-22 10:04:58',22,'Taglieri di salumi, focacce, formaggi freschi, pizza margherita','Pinta Americana','Acqua, malto d\'orzo, luppolo Cascade, lievito','Bottiglia 33','Blonde Ale','chiara'),(2,'Pietra Filosofale','Birra complessa e strutturata con sentori di frutta gialla matura, spezie e miele. Corpo pieno e finale caldo tipico delle Tripel belghe.','Complessa e intensa, con sentori speziati, frutta matura e finale caldo.','Italia','L\'Alchimista del Luppolo',8.50,'pietra-filosofale.webp','8-10°C',3.95,'pietra-filosofale','2026-06-22 10:04:58','2026-06-22 10:04:58',30,'Arrosti, carni bianche, formaggi stagionati','Calice Belga','Acqua, malto d\'orzo, zucchero candito, luppolo Saaz, lievito belga','Bottiglia 33','Belgian Tripel','chiara'),(3,'Fumo di Drago','Porter affumicata con note di legna, cacao amaro, caffè tostato e lieve sentore torbato. Corpo medio e finale persistente.','Scura e affascinante, con note affumicate, cacao e caffè.','Italia','L\'Alchimista del Luppolo',6.80,'fumo-di-drago.webp','10-12°C',3.45,'fumo-di-drago','2026-06-22 10:04:58','2026-06-22 10:04:58',35,'BBQ, costine, hamburger gourmet, carne affumicata','Nonic Pint','Acqua, malto d\'orzo affumicato, malti tostati, luppolo Fuggle, lievito','Bottiglia 33','Smoked Porter','scura'),(4,'Verde Smeraldo','New England IPA velata e succosa con intensi aromi tropicali di mango, ananas e passion fruit. Corpo morbido e amaro moderato.','Esplosione tropicale di mango, passion fruit e agrumi.','Italia','L\'Alchimista del Luppolo',6.50,'verde-smeraldo.webp','7-9°C',3.25,'verde-smeraldo','2026-06-22 10:04:58','2026-06-22 10:04:58',45,'Tacos, burger, cucina asiatica, pollo speziato','Teku','Acqua, malto d\'orzo, avena, luppolo Citra, Mosaic, lievito','Bottiglia 33','New England IPA','chiara'),(5,'Luna d\'Ambra','Birra ambrata equilibrata con note di biscotto, caramello e leggera frutta secca. Finale morbido e armonioso.','Caramello, biscotto e leggere note di frutta secca.','Italia','L\'Alchimista del Luppolo',5.80,'luna-dambra.webp','8-10°C',3.00,'luna-d-ambra','2026-06-22 10:04:58','2026-06-22 10:04:58',28,'Porchetta, carni arrosto, formaggi semi-stagionati','Pinta Inglese','Acqua, malto d\'orzo caramellato, luppolo East Kent Goldings, lievito','Bottiglia 33','Amber Ale','ambrata'),(6,'Notte dell\'Alchimista','Imperial Stout intensa e corposa con aromi di cacao fondente, caffè espresso, vaniglia e frutta sotto spirito.','Corposa e avvolgente, con cacao, vaniglia e caffè tostato.','Italia','L\'Alchimista del Luppolo',10.00,'notte-dellalchimista.webp','12-14°C',4.25,'notte-dell-alchimista','2026-06-22 10:04:58','2026-06-22 10:04:58',60,'Dessert al cioccolato, tiramisù, sigaro e meditazione','Snifter','Acqua, malti tostati, avena, luppolo Magnum, lievito','Bottiglia 33','Imperial Stout','scura'),(7,'45 Lune','Una Amber Ale originale e raffinata che unisce la morbidezza dei malti caramellati alla freschezza speziata dello zenzero fresco. Il colore ambrato brillante anticipa un profilo aromatico ricco di note di biscotto, miele e crosta di pane, impreziosite da delicati accenni agrumati e speziati. In bocca è equilibrata e scorrevole.','Amber Ale morbida e speziata con un elegante tocco di zenzero fresco.','Italia','Almond \'22',6.00,'45-lune.webp','8-10°C',3.25,'45-lune','2026-06-22 10:04:58','2026-06-22 10:04:58',20,'Pollo arrosto, curry vegetali, crostacei','Calice Teku','Acqua, malto d\'orzo, luppolo, lievito, zenzero fresco','Bottiglia 33','Amber Ale allo zenzero','ambrata'),(8,'Pink IPA','Pink IPA è una birra che riesce a combinare carattere e finezza in un perfetto equilibrio. La generosa luppolatura regala profumi intensi di pompelmo, frutta tropicale, uva bianca e agrumi maturi, mentre l\'aggiunta di pepe rosa introduce una sottile nota speziata che arricchisce il bouquet senza sovrastarlo. Il sorso è pieno e aromatico, con un corpo medio che sostiene una vivace componente fruttata. L\'amaro finale è deciso ma armonioso, lasciando il palato pulito e invitando immediatamente a un nuovo sorso.','IPA intensa e profumata con note di pompelmo e frutta tropicale.','Italia','Almond \'22',6.30,'pink-ipa.webp','6-8°C',3.50,'pink-ipa','2026-06-22 10:04:58','2026-06-22 10:04:58',52,'Hamburger gourmet, cucina asiatica','Teku','Acqua, malto d\'orzo, luppoli Simcoe, Nelson Sauvin, Hallertau Saphyr, pepe rosa, lievito','Bottiglia 33','IPA al pepe rosa','ambrata'),(9,'Braveheart','Braveheart rappresenta l\'incontro tra l\'eleganza delle lager e l\'intensità delle birre ad alta gradazione. Nonostante la struttura importante, mantiene una straordinaria bevibilità grazie a una fermentazione pulita che valorizza le note di cereale, miele e pane appena sfornato. Il profilo aromatico è arricchito da sfumature floreali e leggere note erbacee provenienti dai luppoli selezionati. In bocca si presenta morbida e avvolgente, con un corpo pieno ma mai pesante e un finale equilibrato che bilancia perfettamente la componente maltata con una delicata amarezza.','Strong Lager ricca e appagante, con note di cereale e miele.','Italia','Almond \'22',7.50,'braveheart.webp','6-8°C',3.75,'braveheart','2026-06-22 10:04:58','2026-06-22 10:04:58',55,'Salumi stagionati, carne di maiale','Pinta tedesca','Acqua, malto d\'orzo, luppolo, lievito','Bottiglia 33','Imperial Lager','chiara'),(10,'Torbata','Torbata è una delle creazioni più affascinanti di Almond \'22, una birra che sfugge alle classificazioni più comuni e invita a una degustazione lenta e attenta. Ispirata alla tradizione dei Barley Wine inglesi, si distingue per l\'impiego di malto torbato, miele di castagno e scorza d\'arancia, ingredienti che costruiscono un profilo aromatico complesso e stratificato. Al naso emergono sentori di caramello, frutta secca, miele, legno e una delicata affumicatura che ricorda il whisky torbato. In bocca è calda, avvolgente e ricca, con un corpo importante e una lunga persistenza aromatica che evolve sorso dopo sorso.','Barley Wine complesso e avvolgente, ideale da meditazione.','Italia','Almond \'22',7.90,'torbata.webp','10-12°C',4.25,'torbata','2026-06-22 10:04:58','2026-06-22 10:04:58',40,'Formaggi stagionati, brasati, selvaggina','Snifter','Acqua, malto d\'orzo, malto torbato, miele di castagno, scorza d\'arancia, luppolo, lievito','Bottiglia 33','English Barley Wine','rossa'),(11,'Gone Mental','Gone Mental è una West Coast Double IPA che incarna tutta la filosofia della vecchia scuola americana: luppolo protagonista, amaro deciso e una bevuta sorprendentemente pulita. Al naso esplodono intense note di agrumi, scorza di pompelmo, resina di pino e frutta tropicale matura, accompagnate da sfumature erbacee che ne aumentano la complessità aromatica. In bocca il corpo è medio e ben strutturato, sostenuto da una base maltata essenziale che lascia spazio alla generosa luppolatura. Il finale è secco, persistente e caratterizzato da una piacevole amarezza che invita immediatamente a un nuovo sorso.','Un concentrato di luppolo e carattere: agrumi, resina e finale deciso per chi ama IPA intense.','Italia','Antikorpo Brewing',7.50,'gone-mental.webp','6-8°C',3.75,'gone-mental','2026-06-22 10:04:58','2026-06-22 10:04:58',75,'Hamburger, BBQ, cucina messicana','Teku','Acqua, malto d\'orzo, avena, luppolo, lievito','Lattina 40','Double IPA','chiara'),(12,'Grommet GF','Grommet GF è la dimostrazione che una birra senza glutine può mantenere tutto il carattere e la personalità di una vera craft beer. Ispirata alle tradizionali Keller Pils tedesche, si presenta naturalmente torbida e dal colore dorato intenso. Al naso emergono profumi floreali, note erbacee e sentori di pane fresco, mentre al palato conquista con la sua freschezza e la sua impeccabile pulizia gustativa.','Fresca, fragrante e incredibilmente beverina. Una pils artigianale che conquista dal primo sorso.','Italia','Antikorpo Brewing',4.80,'grommet-gf.webp','4-6°C',3.00,'grommet-gf','2026-06-22 10:04:58','2026-06-22 10:04:58',28,'Pizza, fritti, salumi','Pils','Acqua, malto d\'orzo deglutinato, luppolo, lievito','Lattina 40','Keller Pils','chiara'),(13,'Impact Zone','Impact Zone porta nel bicchiere tutta l\'energia dei luppoli dell\'emisfero australe. Questa Pacific Pale Ale si distingue per un bouquet aromatico esplosivo dove mango, frutto della passione, lime e agrumi si intrecciano creando una bevuta fresca e coinvolgente. Il corpo è leggero ma non esile, capace di sostenere una componente aromatica intensa senza risultare eccessiva.','Esplosione di mango, agrumi e frutta tropicale in una pale ale moderna e super scorrevole.','Italia','Antikorpo Brewing',5.00,'impact-zone.webp','5-7°C',3.25,'impact-zone','2026-06-22 10:04:58','2026-06-22 10:04:58',32,'Fish burger, tacos di pesce, poke','Nonic Pint','Acqua, malti Pils e Carapils, luppoli, lievito','Lattina 40','Pacific Pale Ale','chiara'),(14,'Lowrider GF','Lowrider GF rappresenta l\'incontro perfetto tra due mondi: l\'intensità aromatica delle IPA e la pulizia gustativa delle lager. Grazie alla fermentazione a bassa temperatura, la componente maltata rimane discreta e lascia spazio ai profumi di agrumi, frutta tropicale e leggere note resinose donate dalla luppolatura. Il risultato è una birra fresca, moderna e incredibilmente scorrevole, con un finale secco che esalta ulteriormente la componente aromatica..','Tutto il profumo di un\'IPA con la bevibilità di una lager.','Italia','Antikorpo Brewing',5.80,'lowrider-gf.webp','5-7°C',3.50,'lowrider-gf','2026-06-22 10:04:58','2026-06-22 10:04:58',69,'Hot dog gourmet, pollo speziato','Pils','Acqua, malto d\'orzo deglutinato, luppolo, lievito','Lattina 40','India Pale Lager','chiara'),(15,'See Ya In The Pit','See Ya In The Pit è una birra che sfida i confini tra birra e dessert. Questa Imperial Pastry Stout offre un\'esperienza sensoriale intensa e avvolgente, caratterizzata da profonde note di cacao, cioccolato fondente, caffè tostato e scorza d\'arancia candita. La struttura importante e la morbidezza del corpo contribuiscono a creare una bevuta ricca e vellutata che evolve continuamente nel bicchiere.','Un dessert liquido ricco e avvolgente, dove cacao e arancia si incontrano.','Italia','Antikorpo Brewing',8.00,'see-ya-in-the-pit.webp','10-12°C',4.25,'see-ya-in-the-pit','2026-06-22 10:04:58','2026-06-22 10:04:58',35,'Brownie, cheesecake, cioccolato','Snifter','Acqua, malti tostati, luppolo, lievito, arancia candita','Lattina 40','Imperial Pastry Stout','scura'),(16,'Wahine','Wahine è una blanche luminosa e rinfrescante che prende ispirazione dalle classiche birre di frumento belghe, reinterpretandole con l\'aggiunta di pompelmo rosa. Il risultato è una birra dal profilo aromatico estremamente fresco, dove agrumi, spezie leggere e delicati sentori floreali si fondono armoniosamente.In bocca si distingue per la sua leggerezza e per una piacevole nota agrumata che accompagna la bevuta fino al finale, lasciando una sensazione pulita e dissetante.','Profumi agrumati e grande freschezza rendono questa blanche perfetta per l\'estate.','Italia','Antikorpo Brewing',5.10,'wahine.webp','4-6°C',3.25,'wahine','2026-06-22 10:04:58','2026-06-22 10:04:58',15,'Sushi, insalate, pesce bianco','Calice','Acqua, frumento, malto d\'orzo, pompelmo rosa, spezie, lievito','Lattina 40','Blanche al pompelmo rosa','chiara'),(17,'Home Spot','Home Spot è un omaggio alla tradizione delle pils boeme, reinterpretata con l\'approccio moderno e indipendente di Antikorpo Brewery. Il colore dorato brillante e la schiuma compatta anticipano aromi floreali, erbacei e leggermente speziati. Al palato offre una combinazione perfetta tra morbidezza maltata e freschezza luppolata, con un finale secco e pulito che ne esalta la bevibilità.','La classica pils che non stanca mai: fresca, croccante e perfetta per ogni occasione.','Italia','Antikorpo Brewing',4.70,'home-spot.webp','4-6°C',3.00,'home-spot','2026-06-22 10:04:58','2026-06-22 10:04:58',30,'Pizza margherita, focacce, fritti','Pils','Acqua, malto d\'orzo, luppolo Saaz, lievito','Lattina 40','Bohemian Pils','chiara'),(18,'Dreams','Dreams è una birra che va oltre il concetto tradizionale di Barleywine, trasformandosi in una vera esperienza sensoriale. Affinata in botte e caratterizzata da una gradazione importante, sviluppa una complessità straordinaria fatta di caramello scuro, melassa, vaniglia, legno, frutta sotto spirito e richiami ai grandi distillati da invecchiamento. Il corpo è pieno e vellutato, mentre il calore alcolico accompagna una lunghissima persistenza aromatica. Una birra da meditazione che invita a rallentare e dedicare tempo a ogni singolo sorso.','Una birra da meditazione estrema: potente, complessa e ricca di sfumature da distillato.','Austria','Bevog',18.50,'dreams.webp','12-14°C',9.00,'dreams','2026-06-22 10:04:58','2026-06-22 10:04:58',20,'Cioccolato fondente, meditazione','Snifter','Acqua, malto d\'orzo, luppolo, lievito','Bottiglia 33','Barrel Aged Barleywine','scura'),(19,'Ex. Black Rhino','Black Rhino è una Imperial Stout intensa e maestosa, costruita su una base di malti tostati che regalano aromi di caffè espresso, cacao amaro, liquirizia e frutta secca. La struttura è imponente ma perfettamente bilanciata, con una morbidezza che accompagna il palato fino a un finale lungo e appagante. Una birra che esprime forza e raffinatezza allo stesso tempo, pensata per chi ama le interpretazioni più ricche degli stili scuri.','Imperial Stout intensa e vellutata, con profonde note di cacao e caffè.','Austria','Bevog',9.60,'ex-black-rhino.webp','10-12°C',4.25,'ex--black-rhino','2026-06-22 10:04:58','2026-06-22 10:04:58',65,'Brownie, fondente','Snifter','Acqua, malto d\'orzo, luppolo, lievito','Lattina 40','Imperial Stout','scura'),(20,'Ex. Flying Frog','Flying Frog rappresenta tutto ciò che si ama delle moderne New England IPA. Torbida e luminosa nel bicchiere, sprigiona profumi intensi di mango, ananas, pesca e agrumi maturi. Il corpo morbido e vellutato accompagna una componente fruttata esplosiva che domina la bevuta, mentre l\'amaro rimane delicato e perfettamente integrato. Una IPA succosa e contemporanea che conquista sia gli appassionati sia chi cerca un approccio più morbido al mondo delle birre luppolate.','Mango, ananas e agrumi in una IPA morbida e moderna.','Austria','Bevog',6.00,'ex-flying-frog.webp','6-8°C',3.75,'ex--flying-frog','2026-06-22 10:04:58','2026-06-22 10:04:58',35,'Burger gourmet','Teku','Acqua, malto d\'orzo, avena, luppolo, lievito','Lattina 40','NEIPA','chiara'),(21,'Ex. Pangolin','Pangolin è una Sour Ale che mette al centro freschezza ed equilibrio. L\'acidità vivace ma controllata dona energia alla bevuta senza risultare aggressiva, mentre il profilo aromatico sviluppa eleganti sfumature agrumate e fruttate. Il finale asciutto e pulito la rende estremamente dissetante e sorprendentemente facile da bere nonostante la sua complessità.','Acidità elegante e grande bevibilità.','Austria','Bevog',6.70,'ex-pangolin.webp','5-7°C',3.75,'ex--pangolin','2026-06-22 10:04:58','2026-06-22 10:04:58',8,'Formaggi freschi, sushi','Calice','Acqua, malto d\'orzo, luppolo, lievito','Lattina 40','Sour Ale','chiara'),(22,'Ex. Orangutan','Orangutan è una birra che unisce due mondi apparentemente lontani: l\'acidità vibrante delle sour e l\'intensità aromatica delle IPA moderne. La doppia luppolatura a freddo amplifica le note di mango, passion fruit e agrumi, mentre la componente acida dona profondità e freschezza. Il risultato è una birra sorprendente, complessa e incredibilmente dinamica.','L\'acidità di una sour incontra la carica aromatica di una IPA moderna.','Austria','Bevog',6.70,'ex-orangutan.webp','6-8°C',4.00,'ex--orangutan','2026-06-22 10:04:58','2026-06-22 10:04:58',25,'Cucina asiatica','Teku','Acqua, malto d\'orzo, luppolo, lievito','Lattina 40','DDH Sour IPA','chiara'),(23,'Ex. Rabbit','Rabbit è la dimostrazione di quanto una pils possa essere moderna senza perdere la propria identità. La base lager pulita lascia spazio a una luppolatura aromatica che regala sentori floreali, erbacei e agrumati. Il corpo leggero e il finale secco ne esaltano la bevibilità, rendendola una compagna ideale per ogni momento della giornata.','Pils moderna con aromi erbacei e agrumati.','Austria','Bevog',4.10,'ex-rabbit.webp','4-6°C',3.00,'ex--rabbit','2026-06-22 10:04:58','2026-06-22 10:04:58',35,'Pizza e aperitivo','Pils','Acqua, malto d\'orzo, luppolo, lievito','Lattina 40','Hoppy Pils','chiara'),(24,'Ex. Snow Leopard','Snow Leopard è una Imperial Stout opulenta e avvolgente che combina la profondità dei malti tostati con la morbidezza del cocco. Al naso emergono note di cacao, caffè, vaniglia e cocco tostato, mentre il corpo pieno e setoso accompagna una bevuta intensa ma incredibilmente equilibrata. Una birra pensata per chi cerca ricchezza aromatica e grande complessità.','Imperial Stout opulenta con cocco tostato, cacao e caffè.','Austria','Bevog',9.50,'ex-snow-leopard.webp','10-12°C',4.75,'ex--snow-leopard','2026-06-22 10:04:58','2026-06-22 10:04:58',55,'Cheesecake al cioccolato','Snifter','Acqua, malto d\'orzo, cocco, luppolo, lievito','Lattina 40','Imperial Stout','scura'),(25,'Helles Export','Helles Export rende omaggio alla tradizione bavarese con una lager elegante, pulita e perfettamente equilibrata. I profumi di pane fresco, miele delicato e cereale accompagnano un sorso morbido e scorrevole, sostenuto da una leggera componente erbacea dei luppoli. Una birra apparentemente semplice che rivela grande precisione tecnica e straordinaria bevibilità.','Morbide note maltate e grande scorrevolezza.','Austria','Bevog',4.60,'helles-export.webp','4-6°C',2.75,'helles-export','2026-06-22 10:04:58','2026-06-22 10:04:58',20,'Brezel e wurstel','Boccale bavarese','Acqua, malto d\'orzo, luppolo, lievito','Lattina 33','Helles','chiara'),(26,'Nitro Porter Coconut','Grazie alla tecnologia Nitro, questa Porter sviluppa una texture incredibilmente cremosa e una schiuma compatta e persistente. Le note di cocco si intrecciano con cacao, caffè e caramello creando una bevuta morbida e vellutata. Ogni sorso richiama le sensazioni di un dessert artigianale, mantenendo però l\'equilibrio e la bevibilità tipici delle migliori porter.','Morbida, cremosa e irresistibile.','Austria','Bevog',5.50,'nitro-porter-coconut.webp','8-10°C',3.25,'nitro-porter-coconut','2026-06-22 10:04:58','2026-06-22 10:04:58',10,'Dessert al cacao','Nonic Pint','Acqua, malto d\'orzo, cocco, luppolo, lievito','Lattina 33','Porter','scura'),(27,'Kramah','Kramah è probabilmente una delle birre simbolo di Bevog. Una IPA esplosiva che mette in mostra tutto il potenziale dei luppoli americani e neozelandesi. Profumi intensi di mango, litchi, ananas, pompelmo e resina anticipano un sorso pieno e aromatico, sostenuto da una struttura equilibrata e da un finale lungo e amaricante. Una birra che non lascia indifferenti e che rappresenta perfettamente il lato più moderno della scuola IPA.','Una IPA esplosiva e moderna ricca di frutta tropicale.','Austria','Bevog',6.50,'kramah.webp','8-10°C',3.25,'kramah','2026-06-22 10:04:58','2026-06-22 10:04:58',70,'Hamburger, BBQ','Teku','Acqua, malto d\'orzo, luppolo, lievito','Lattina 33','American IPA','chiara'),(28,'Lolita','Lolita è una sour delicata e seducente che gioca sull\'equilibrio tra acidità e frutta. Lampone e rabarbaro regalano profumi freschi e invitanti, mentre il corpo leggero e la gradazione contenuta la rendono estremamente facile da bere. Una birra vivace, elegante e perfetta per chi cerca qualcosa di diverso dalle classiche birre estive.','Fresca, fruttata e dissetante.','Austria','Bevog',3.50,'lolita.webp','4-6°C',2.75,'lolita','2026-06-22 10:04:58','2026-06-22 10:04:58',18,'Dessert ai frutti rossi','Calice','Acqua, malto d\'orzo, frumento, lampone, rabarbaro, lievito','Lattina 33','Berliner Weisse ','ambrata'),(29,'Lola','Lola è una sour fresca e spensierata, caratterizzata da un\'esplosione di piccoli frutti rossi. Lampone e ribes donano un profilo aromatico intenso ma armonioso, mentre la tipica acidità della Berliner Weisse mantiene la bevuta leggera e dissetante. Una birra perfetta per chi ama i sapori fruttati e le fermentazioni acide più accessibili.','Lampone e ribes regalano una bevuta fresca e irresistibile.','Austria','Bevog',3.50,'lola.webp','4-6°C',3.00,'lola','2026-06-22 10:04:58','2026-06-22 10:04:58',5,'Dessert ai frutti rossi','Calice','Acqua, malto d\'orzo, frumento, lampone, ribes, lievito','Lattina 33','Berliner Weisse ','ambrata'),(30,'Ond','Ond è una porter che affascina per il suo equilibrio tra tostature e affumicatura. Le note di cacao, caffè e caramello si fondono con una delicata componente fumé che richiama legno e torba senza mai risultare invadente. Il corpo morbido e il finale persistente rendono ogni sorso ricco di sfumature e particolarmente appagante.','Tostature profonde e affumicatura elegante.','Austria','Bevog',6.30,'ond.webp','10-12°C',3.25,'ond','2026-06-22 10:04:58','2026-06-22 10:04:58',32,'Costine BBQ','Snifter','Acqua, malto d\'orzo, malti affumicati, luppolo, lievito','Lattina 33','Smoked Porter','scura'),(31,'Rudeen','Rudeen combina il meglio di due mondi: il carattere tostato delle birre scure e l\'esuberanza aromatica delle IPA. Il risultato è una Black IPA complessa e coinvolgente, dove note di cacao e caffè si intrecciano con agrumi, resina e frutta tropicale. Il finale è secco e decisamente luppolato, lasciando una sensazione intensa e persistente.','Il meglio di una IPA e di una stout.','Austria','Bevog',7.40,'rudeen.webp','8-10°C',3.75,'rudeen','2026-06-22 10:04:58','2026-06-22 10:04:58',75,'BBQ e hamburger affumicati','Teku','Acqua, malto d\'orzo, luppolo, lievito','Lattina 33','Black IPA','scura'),(32,'Andiamo','Nata dalla collaborazione tra Bevog e Freigeist Bierkultur, Andiamo è una birra fuori dagli schemi che unisce la profondità di una porter all\'acidità elegante di una sour. Le note tostate di cacao e caffè vengono alleggerite da una componente acida raffinata che rende la bevuta sorprendentemente fresca e dinamica. Una creazione originale e audace, pensata per chi ama esplorare nuovi territori brassicoli.','Tostature morbide e acidità elegante.','Austria','Bevog / Freigeist Bierkultur',6.00,'andiamo.webp','8-10°C',4.00,'andiamo','2026-06-22 10:04:58','2026-06-22 10:04:58',28,'Formaggi erborinati','Calice','Acqua, malto d\'orzo, luppolo, lievito','Bottiglia 33','Sour Porter','scura'),(33,'Bohemian Pilsner','Bohemian Pilsner è l\'interpretazione di Eight Degrees di uno degli stili più iconici della tradizione europea. Ispirata alle storiche lager della Repubblica Ceca, si presenta con un brillante colore dorato e una schiuma fine e persistente. Al naso emergono note di crosta di pane, cereale fresco e delicati sentori floreali ed erbacei provenienti dai luppoli nobili. In bocca è elegante e scorrevole, con una piacevole morbidezza maltata che si fonde armoniosamente con un finale secco e leggermente amaricante.','Pils elegante e scorrevole, perfetta per ogni occasione.','Irlanda','Eight Degrees Brewing',4.00,'bohemian-pilsner.webp','4-6°C',3.00,'bohemian-pilsner','2026-06-22 10:04:58','2026-06-22 10:04:58',30,'Pizza, salumi','Pils','Acqua, malto d\'orzo, luppolo, lievito','Lattina 40','Bohemian Pils','chiara'),(34,'Original Gravity Juicy IPA','Original Gravity è una Juicy IPA moderna che mette al centro la componente aromatica del luppolo. Fin dal primo approccio al bicchiere sprigiona intensi profumi di mango, ananas, pesca e agrumi maturi, creando un bouquet ricco e coinvolgente. Il corpo morbido e vellutato accompagna una bevuta succosa e avvolgente, mentre l\'amaro rimane contenuto per lasciare spazio alla componente fruttata.','Succosa e profumata, ideale per gli amanti delle IPA moderne.','Irlanda','Eight Degrees Brewing',6.00,'original-gravity-juicy-ipa.webp','6-8°C',3.75,'original-gravity-juicy-ipa','2026-06-22 10:04:58','2026-06-22 10:04:58',40,'Hamburger, tacos','Teku','Acqua, malto d\'orzo, luppolo, lievito','Lattina 40','Juicy IPA','chiara'),(35,'Citra','Citra celebra uno dei luppoli più iconici e amati al mondo. Realizzata utilizzando il celebre luppolo Citra come protagonista assoluto, offre un\'esplosione aromatica di pompelmo, lime, mango, frutto della passione e leggere sfumature resinose. La base maltata rimane volutamente discreta per valorizzare ogni sfumatura del luppolo, mentre il finale regala una piacevole amarezza persistente.','Agrumi e frutta tropicale in una IPA fresca e aromatica.','Irlanda','Eight Degrees Brewing',5.70,'citra.webp','6-8°C',3.50,'citra','2026-06-22 10:04:58','2026-06-22 10:04:58',55,'BBQ, pollo speziato','Teku','Acqua, malto d\'orzo, luppolo Citra, lievito','Lattina 40','Single Hop IPA','chiara'),(36,'Howling Gale','Howling Gale è una delle birre simbolo di Eight Degrees e rappresenta perfettamente il carattere della moderna scena brassicola irlandese. Al naso si apre con note di agrumi, fiori di campo e leggere sfumature erbacee, mentre il corpo leggero e la gradazione contenuta la rendono estremamente bevibile. Il finale bilancia perfettamente la componente maltata con una delicata amarezza che accompagna il sorso senza risultare invasiva.','Una birra facile da bere ma ricca di carattere.','Irlanda','Eight Degrees Brewing',4.50,'howling-gale.webp','5-7°C',3.25,'howling-gale','2026-06-22 10:04:58','2026-06-22 10:04:58',35,'Fish & chips, panini','Nonic Pint','Acqua, malto d\'orzo, luppolo, lievito','Lattina 40','Irish Pale Ale','ambrata'),(37,'Knockmealdown','Prende il nome dalle montagne che dominano la regione in cui sorge il birrificio e rappresenta una delle espressioni più autentiche della tradizione irlandese. Knockmealdown offre un profilo aromatico ricco di caffè tostato, cacao amaro e leggere note di pane nero. Il corpo medio e la morbidezza della schiuma accompagnano una bevuta equilibrata, dove le tostature rimangono protagoniste senza risultare aggressive.','Morbida e tostata, perfetta per gli amanti delle birre scure.','Irlanda','Eight Degrees Brewing',5.00,'knockmealdown.webp','8-10°C',3.25,'knockmealdown','2026-06-22 10:04:58','2026-06-22 10:04:58',30,'Dolci al cioccolato, ostriche','Pinta','Acqua, malto d\'orzo tostato, luppolo, lievito','Lattina 40','Irish Stout','scura'),(38,'Seisiún','Il termine irlandese \"Seisiún\" richiama i tradizionali incontri musicali nei pub, e questa birra incarna perfettamente quello spirito conviviale. Pur mantenendo una gradazione contenuta, offre un profilo aromatico sorprendentemente intenso, caratterizzato da agrumi, frutta tropicale e leggere note erbacee. Il corpo snello e il finale secco la rendono incredibilmente scorrevole e dissetante.','Tanta freschezza e aroma con una gradazione contenuta.','Irlanda','Eight Degrees Brewing',4.50,'seisiun.webp','5-7°C',3.25,'seisi-n','2026-06-22 10:04:58','2026-06-22 10:04:58',40,'Street food, pizza','Teku','Acqua, malto d\'orzo, luppolo, lievito','Lattina 40','Session IPA','chiara'),(39,'Sunburnt','Sunburnt reinterpreta la tradizionale Red Ale irlandese con un approccio moderno e dinamico. Il colore rosso ramato anticipa aromi di caramello, biscotto e crosta di pane, accompagnati da leggere sfumature fruttate e floreali. Al palato il malto domina elegantemente la scena, regalando una dolcezza equilibrata che viene bilanciata da una delicata componente amaricante nel finale.','Equilibrata e avvolgente, con piacevoli sentori maltati.','Irlanda','Eight Degrees Brewing',5.00,'sunburnt.webp','6-8°C',3.25,'sunburnt','2026-06-22 10:04:58','2026-06-22 10:04:58',25,'Carni arrosto, cheddar','Nonic Pint','Acqua, malto d\'orzo, luppolo, lievito','Lattina 40','Irish Red Ale','rossa'),(40,'The Full Irish','The Full Irish è una birra che celebra il patrimonio agricolo e brassicolo dell\'Irlanda. Realizzata utilizzando esclusivamente malto irlandese, combina la ricchezza della materia prima locale con una luppolatura moderna e aromatica. Al naso emergono note di agrumi, frutta tropicale e miele, mentre il corpo pieno e la base maltata donano profondità e carattere alla bevuta. Il finale è deciso ma equilibrato, con una piacevole persistenza aromatica.','Corpo pieno e aromi intensi per una IPA dal carattere autentico.','Irlanda','Eight Degrees Brewing',6.00,'the-full-irish.webp','6-8°C',3.50,'the-full-irish','2026-06-22 10:04:58','2026-06-22 10:04:58',60,'Hamburger gourmet, BBQ','Teku','Acqua, malto d\'orzo, luppolo, lievito','Lattina 40','Single Malt IPA','chiara'),(41,'Gueuze','La Gueuze di Cantillon è considerata da molti appassionati la quintessenza dello stile e una delle massime espressioni della tradizione brassicola belga. Nasce dall\'assemblaggio di Lambic di diverse annate, affinati in botte e successivamente rifermentati in bottiglia. Acidità complessa, note rustiche, agrumate e minerali con finale secco.','L\'icona delle Gueuze belghe: elegante, complessa e vivace, con un perfetto equilibrio tra acidità, freschezza e profondità aromatica.','Belgio','Brasserie Cantillon',5.00,'gueuze.webp','10-12°C',6.00,'gueuze','2026-06-22 10:04:58','2026-06-22 10:04:58',10,'Formaggi erborinati, ostriche, pesce affumicato','Calice a tulipano','Acqua, malto d\'orzo, frumento non maltato, luppolo invecchiato','Bottiglia 33','Gueuze (Blend di Lambic)','chiara'),(42,'Rosé de Gambrinus','Rosé de Gambrinus è probabilmente una delle creazioni più eleganti e affascinanti di Cantillon. Ottenuta attraverso la macerazione di grandi quantità di lamponi freschi all\'interno del Lambic, riesce a trasformare la frutta in un elemento perfettamente integrato senza mai risultare dolce o artificiale. Acidità elegante, intensa componente fruttata e finale secco.','Un capolavoro di freschezza e frutta: lamponi intensi, acidità raffinata e una bevuta incredibilmente elegante.','Belgio','Brasserie Cantillon',5.00,'rose-de-gambrinus.webp','8-10°C',6.75,'ros--de-gambrinus','2026-06-22 10:04:59','2026-06-22 10:04:59',10,'Cheesecake, foie gras, dessert ai frutti rossi','Calice','Acqua, malto d\'orzo, frumento non maltato, lamponi freschi, luppolo invecchiato','Bottiglia 33','Lambic alla Framboise','rossa'),(43,'Kriek','La Kriek di Cantillon rappresenta una delle interpretazioni più autentiche e tradizionali di questo storico stile belga. Viene prodotta utilizzando ciliegie intere della varietà Schaerbeek, lasciate macerare nel Lambic per diversi mesi affinché il frutto possa esprimere tutta la propria ricchezza aromatica e contribuire alla fermentazione naturale. Profilo complesso con acidità vibrante e marcata componente fruttata.','L\'equilibrio perfetto tra ciliegia fresca, acidità naturale e complessità delle fermentazioni spontanee.','Belgio','Brasserie Cantillon',5.00,'kriek.webp','8-10°C',6.75,'kriek','2026-06-22 10:04:59','2026-06-22 10:04:59',10,'Anatra, selvaggina, crostate alle ciliegie','Calice','Acqua, malto d\'orzo, frumento non maltato, ciliegie Schaerbeek, luppolo invecchiato','Bottiglia 33','Lambic alle ciliegie','rossa'),(44,'Apollo','Come il dio della luce da cui prende il nome, Apollo è una birra luminosa, intensa e capace di lasciare il segno. Questa Double IPA sprigiona fin dal primo istante un\'esplosione di aromi tropicali e agrumati, con note di mango, ananas, pompelmo e scorza d\'arancia che emergono con grande intensità. La struttura importante e la gradazione elevata sono perfettamente bilanciate da una luppolatura moderna che regala un finale secco e persistente.','Esplosione di frutta tropicale e agrumi in una Double IPA intensa ma equilibrata.','Italia','Epica',8.00,'apollo.webp','6-8°C',3.75,'apollo','2026-06-22 10:04:59','2026-06-22 10:04:59',60,'BBQ, hamburger gourmet','Teku','Acqua, malto d\'orzo, luppolo, lievito','Bottiglia 33','Double IPA','chiara'),(45,'Ares','Ares incarna tutta la forza e l\'intensità del dio della guerra. Nera come la notte e caratterizzata da una schiuma compatta e cremosa, sviluppa profumi profondi di caffè tostato, cacao amaro, liquirizia e malto torrefatto. Il corpo pieno e la consistenza vellutata accompagnano una bevuta ricca e appagante che evolve lentamente nel bicchiere.','Corposa e avvolgente, perfetta per chi ama le birre scure e intense.','Italia','Epica',7.00,'ares.webp','10-12°C',3.75,'ares','2026-06-22 10:04:59','2026-06-22 10:04:59',45,'Cioccolato fondente, formaggi erborinati','Snifter','Acqua, malto d\'orzo tostato, luppolo, lievito','Bottiglia 33','Imperial Stout','scura'),(46,'Cerere','Ispirata alla dea della fertilità e dell\'abbondanza, Cerere celebra la ricchezza dei cereali attraverso una classica interpretazione dello stile Weizen. Al naso emergono le tipiche note di banana matura, chiodo di garofano e pane fresco che caratterizzano le migliori birre di frumento tedesche. In bocca è morbida, fresca e incredibilmente scorrevole, con una carbonazione vivace che ne esalta la bevibilità.','Fresca e fragrante, ideale per accompagnare le giornate più calde.','Italia','Epica',5.20,'cerere.webp','5-7°C',3.00,'cerere','2026-06-22 10:04:59','2026-06-22 10:04:59',15,'Wurstel, insalate','Weizen','Acqua, malto d\'orzo, frumento, lievito','Bottiglia 33','Weizen','chiara'),(47,'Eolo','Come il dio dei venti, Eolo porta con sé una piacevole sensazione di freschezza. Questa Pale Ale si distingue per il perfetto equilibrio tra componente maltata e aromi luppolati. Profumi floreali, agrumati e leggermente erbacei introducono una bevuta semplice ma mai banale, caratterizzata da un corpo leggero e da un finale pulito e armonioso.','Birra facile da bere con eleganti note floreali e agrumate.','Italia','Epica',4.90,'eolo.webp','6-8°C',3.00,'eolo','2026-06-22 10:04:59','2026-06-22 10:04:59',30,'Panini, salumi','Nonic Pint','Acqua, malto d\'orzo, luppolo, lievito','Bottiglia 33','Pale Ale','chiara'),(48,'Kore','Kore nasce dall\'incontro tra due mondi apparentemente lontani: la freschezza speziata delle Blanche belghe e l\'intensità aromatica delle moderne IPA. Il risultato è una birra elegante e originale, caratterizzata da note di agrumi, coriandolo, pepe rosa e frutta tropicale. Il corpo leggero e il finale asciutto ne esaltano la bevibilità, mentre la luppolatura dona profondità e complessità aromatica.','La freschezza di una blanche incontra il carattere di una IPA.','Italia','Epica',4.70,'kore.webp','5-7°C',3.25,'kore','2026-06-22 10:04:59','2026-06-22 10:04:59',40,'Pesce, sushi','Teku','Acqua, malto d\'orzo, frumento, pepe rosa, luppolo, lievito','Bottiglia 33','White IPA','chiara'),(49,'Medusa','Medusa affascina e cattura proprio come il personaggio mitologico da cui prende il nome. Questa Dubbel belga offre un profilo aromatico ricco di caramello, uvetta, datteri e frutta secca, accompagnato da leggere sfumature speziate tipiche dei lieviti d\'abbazia. Il corpo è pieno e avvolgente, mentre il finale caldo e persistente invita a una degustazione lenta e meditativa.','Calda e avvolgente, perfetta per gli amanti degli stili belgi.','Italia','Epica',8.00,'medusa.webp','8-10°C',3.50,'medusa','2026-06-22 10:04:59','2026-06-22 10:04:59',20,'Arrosti, formaggi stagionati','Calice','Acqua, malto d\'orzo, luppolo, lievito','Bottiglia 33','Dubbel','ambrata'),(50,'Epichristmas','Epichristmas racchiude nel bicchiere tutta l\'atmosfera delle festività. Ispirata alle tradizionali birre natalizie del Nord Europa, offre un ricco bouquet di spezie, miele, frutta candita e caramello. Il corpo caldo e morbido accompagna una bevuta intensa e avvolgente che richiama immediatamente il periodo invernale e i momenti trascorsi in compagnia.','Il calore delle feste in una birra intensa e profumata.','Italia','Epica',8.00,'epichristmas.webp','10-12°C',4.00,'epichristmas','2026-06-22 10:04:59','2026-06-22 10:04:59',22,'Dolci natalizi, panettone','Calice','Acqua, malto d\'orzo, spezie, luppolo, lievito','Bottiglia 33','Belgian Strong Ale','ambrata'),(51,'Pan','Pan è una Brown Ale originale che valorizza le pregiate nocciole dei Nebrodi, creando un perfetto equilibrio tra tradizione brassicola e territorio siciliano. I profumi di nocciola tostata si intrecciano a sentori di biscotto, cacao e caramello, dando vita a una bevuta morbida, elegante e sorprendentemente equilibrata.','Morbida e maltata con irresistibili note di nocciola.','Italia','Epica',4.70,'pan.webp','8-10°C',3.25,'pan','2026-06-22 10:04:59','2026-06-22 10:04:59',20,'Dolci secchi, formaggi','Nonic Pint','Acqua, malto d\'orzo, nocciole, luppolo, lievito','Bottiglia 33','Brown Ale alle nocciole','ambrata'),(52,'Polifemo','Come il ciclope da cui prende il nome, Polifemo è una birra dal carattere forte e inconfondibile. La base maltata regala note di caramello, biscotto e crosta di pane, mentre la luppolatura americana aggiunge sfumature agrumate e resinose che rendono la bevuta più dinamica e moderna. Il risultato è una Amber Ale strutturata ma estremamente equilibrata.','Equilibrio perfetto tra malto, agrumi e resina.','Italia','Epica',6.00,'polifemo.webp','6-8°C',3.25,'polifemo','2026-06-22 10:04:59','2026-06-22 10:04:59',40,'Pizza, hamburger','Teku','Acqua, malto d\'orzo, luppolo, lievito','Bottiglia 33','American Pale Ale','ambrata'),(53,'Tifeo','Tifeo prende ispirazione dal gigante della mitologia greca e si presenta come una Belgian Ale ricca di personalità. I lieviti belgi regalano profumi fruttati e speziati che si intrecciano a una morbida base maltata. Il corpo medio e la gradazione importante vengono bilanciati da una bevuta elegante e scorrevole, caratterizzata da una piacevole persistenza aromatica.','Ricca, fruttata e speziata con finale elegante.','Italia','Epica',6.70,'tifeo.webp','8-10°C',3.50,'tifeo','2026-06-22 10:04:59','2026-06-22 10:04:59',17,'Formaggi stagionati, carni bianche','Calice','Acqua, malto d\'orzo, miele di ape nera siciliana, luppolo, lievito','Bottiglia 33','Belgian Ale','ambrata'),(54,'Gose to Hollywood','Gose to Hollywood è una reinterpretazione moderna di uno degli stili tedeschi più affascinanti e particolari. Leggera, fresca e incredibilmente dissetante, combina una delicata acidità lattica con una sottile nota salina che ne esalta la bevibilità. Al naso emergono profumi agrumati, sentori di frumento e leggere sfumature speziate che introducono una bevuta agile e sorprendentemente complessa.','Acida, fresca e incredibilmente dissetante, perfetta per l\'estate.','Danimarca','To Øl',3.80,'gose-to-hollywood.webp','4-6°C',2.75,'gose-to-hollywood','2026-06-22 10:04:59','2026-06-22 10:04:59',8,'Pesce, sushi, aperitivo','Calice','Acqua, malto d\'orzo, frumento, sale, coriandolo, lievito','Bottiglia 33','Gose','chiara'),(55,'House of Pale','House of Pale rappresenta l\'essenza della moderna Pale Ale secondo To Øl. Il profilo aromatico è dominato da agrumi, pompelmo, frutta tropicale e leggere note floreali che si sviluppano con eleganza senza risultare invadenti. La base maltata sostiene perfettamente la luppolatura, creando un equilibrio che rende la bevuta appagante e incredibilmente scorrevole.','Una pale ale equilibrata e profumata che invita subito al sorso successivo.','Danimarca','To Øl',5.50,'house-of-pale.webp','5-7°C',3.25,'house-of-pale','2026-06-22 10:04:59','2026-06-22 10:04:59',35,'Hamburger, tacos, pizza','Nonic Pint','Acqua, malto d\'orzo, luppolo, lievito','Bottiglia 33','American Pale Ale','chiara'),(56,'Implosion','Implosion è una delle migliori dimostrazioni di come una birra a bassissimo contenuto alcolico possa offrire un\'esperienza aromatica completa e soddisfacente. Grazie a una luppolatura generosa, sviluppa profumi di agrumi, frutta tropicale e leggere note resinose che ricordano una classica American Pale Ale.','Tutto il gusto di una craft beer con solo lo 0,3% di alcol.','Danimarca','To Øl',0.30,'implosion.webp','4-6°C',2.25,'implosion','2026-06-22 10:04:59','2026-06-22 10:04:59',25,'Snack, panini, aperitivo','Nonic Pint','Acqua, malto d\'orzo, luppolo, lievito','Bottiglia 33','Session APA Analcolica','chiara'),(57,'Santa Gose','Santa Gose prende la tradizione tedesca della Gose e la reinterpreta con lo stile creativo e contemporaneo di To Øl. L\'acidità delicata si fonde con una piacevole sapidità e con leggere sfumature speziate che rendono la bevuta estremamente dinamica. Il corpo leggero e la carbonazione vivace contribuiscono a creare una sensazione di freschezza costante.','Una sour leggera e vivace che sorprende per equilibrio e freschezza.','Danimarca','To Øl',4.00,'santa-gose.webp','4-6°C',2.75,'santa-gose','2026-06-22 10:04:59','2026-06-22 10:04:59',10,'Pesce crudo, crostacei','Calice','Acqua, malto d\'orzo, frumento, sale, coriandolo, lievito','Bottiglia 33','Gose','chiara'),(58,'Snuble Juice','Snuble Juice concentra tutto ciò che si ama delle IPA moderne in una versione più leggera e facile da bere. Al naso esplodono profumi di mango, ananas, frutto della passione e agrumi maturi, mentre il corpo snello e la gradazione contenuta mantengono la bevuta fresca e dinamica.','Poca gradazione ma tantissimo aroma di luppolo.','Danimarca','To Øl',4.50,'snuble-juice.webp','5-7°C',3.00,'snuble-juice','2026-06-22 10:04:59','2026-06-22 10:04:59',40,'Street food, burger','Teku','Acqua, malto d\'orzo, luppolo, lievito','Lattina 33','Session IPA','chiara'),(59,'Tropical Rumble','Tropical Rumble è un\'esplosione di frutta esotica racchiusa in una birra estremamente equilibrata e scorrevole. Mango, ananas, passion fruit e agrumi dominano il profilo aromatico, creando una sensazione quasi da succo tropicale appena spremuto. Il corpo morbido sostiene la componente aromatica senza appesantire la bevuta, mentre il finale leggermente amaro dona profondità e pulizia.','Fresca, tropicale e facilissima da bere.','Danimarca','To Øl',5.00,'tropical-rumble.webp','5-7°C',3.25,'tropical-rumble','2026-06-22 10:04:59','2026-06-22 10:04:59',42,'Pollo speziato, tacos','Teku','Acqua, malto d\'orzo, luppolo, lievito','Lattina 33','Session IPA','chiara'),(60,'Amen','Amen è una American IPA che celebra tutto ciò che gli amanti del luppolo cercano in una birra moderna: aromi esplosivi, freschezza e grande bevibilità. Al naso si apre con un intenso bouquet di agrumi, pompelmo, scorza d\'arancia e leggere note resinose che richiamano le grandi IPA della tradizione americana. Il corpo è snello e dinamico, permettendo alla componente aromatica di esprimersi al meglio senza appesantire la bevuta.','Un classico per gli amanti del luppolo: intensa, aromatica e irresistibilmente beverina.','Italia','WAR',5.00,'amen.webp','6-8°C',3.25,'amen','2026-06-22 10:04:59','2026-06-22 10:04:59',55,'Hamburger, BBQ, cucina tex-mex','Teku','Acqua, malto d\'orzo, luppolo, lievito','Lattina 33','American IPA','chiara'),(61,'Rage','Rage è una West Coast IPA che non fa nulla per nascondere il proprio carattere. Fin dal primo approccio sprigiona intensi profumi di pino, pompelmo, agrumi maturi e leggere sfumature erbacee. Il corpo medio sostiene una luppolatura generosa che domina la bevuta senza risultare eccessiva.','Agrumi, resina e un finale amaro che conquista dal primo sorso.','Italia','WAR',7.00,'rage.webp','6-8°C',3.75,'rage','2026-06-22 10:04:59','2026-06-22 10:04:59',70,'Carni grigliate, pulled pork','Teku','Acqua, malto d\'orzo, luppolo, lievito','Lattina 33','West Coast IPA','chiara'),(62,'Pesci in Faccia','IPA dal profilo aromatico intenso e moderno. I generosi dry hopping esaltano note di frutta tropicale, agrumi maturi e resina. Corpo morbido, amaro deciso ma equilibrato e finale persistente.','IPA esplosiva e profumata con sentori tropicali, agrumati e resinosi, dal carattere intenso e contemporaneo.','Italia','WAR',7.00,'pesci-in-faccia.webp','5-8°C',3.25,'pesci-in-faccia','2026-06-22 10:04:59','2026-06-22 10:04:59',55,'amburger gourmet, tacos speziati, cucina messicana, pollo fritto, formaggi erborinati','Teku','Acqua, malto d\'orzo, avena, frumento, luppolo Citra, Mosaic, Simcoe, lievito','Lattina 33','American IPA','chiara'),(63,'Franco','Franco è l\'esempio perfetto di come una pils possa essere semplice solo in apparenza. Ispirata alla tradizione tedesca delle Keller Pils, si presenta con un colore dorato luminoso e una schiuma compatta. Al naso emergono note di cereale fresco, pane bianco e delicati sentori floreali ed erbacei.','Croccante, fresca e incredibilmente scorrevole.','Italia','WAR',4.80,'franco.webp','4-6°C',3.00,'franco','2026-06-22 10:04:59','2026-06-22 10:04:59',28,'Pizza, focacce, salumi','Pils','Acqua, malto d\'orzo, luppolo, lievito','Lattina 33','Keller Pils','chiara'),(64,'Siena','Siena rappresenta uno degli stili più originali e identitari della scena brassicola italiana. Questa New England Grape Ale unisce il mondo della birra artigianale a quello del vino attraverso l\'utilizzo di mosto d\'uva, creando una bevuta elegante e ricca di sfumature.','L\'incontro perfetto tra vino e birra in una bevuta elegante e aromatica.','Italia','WAR',6.50,'siena.webp','6-8°C',3.75,'siena','2026-06-22 10:04:59','2026-06-22 10:04:59',35,'Formaggi freschi, aperitivo','Calice Teku','Acqua, malto d\'orzo, mosto d\'uva, luppolo, lievito','Lattina 33','New England Grape Ale','ambrata'),(65,'Gioia','Gioia è una Blanche che porta nel bicchiere tutta la freschezza e la spensieratezza delle classiche birre belghe di frumento. Il profilo aromatico è dominato da scorza d\'arancia, coriandolo e leggere note floreali che donano grande vivacità alla bevuta.','Fresca, leggera e perfetta per le giornate più calde.','Italia','WAR',5.00,'gioia.webp','4-6°C',3.00,'gioia','2026-06-22 10:04:59','2026-06-22 10:04:59',15,'Pesce, sushi, insalate','Calice','Acqua, malto d\'orzo, frumento, coriandolo, scorza d\'arancia, lievito','Lattina 33','Blanche','chiara'),(66,'Miami 82','Miami 82 è una lager che richiama atmosfere estive, tramonti sul mare e leggerezza. Dietro la sua apparente semplicità si nasconde una grande cura produttiva che valorizza la pulizia aromatica e la facilità di bevuta. Al naso emergono note di cereale fresco, miele delicato e leggere sfumature erbacee.','Una lager artigianale perfetta per ogni momento della giornata.','Italia','WAR',5.00,'miami-82.webp','4-6°C',2.75,'miami-82','2026-06-22 10:04:59','2026-06-22 10:04:59',20,'Pizza, panini, fritti','Pils','Acqua, malto d\'orzo, luppolo, lievito','Lattina 33','Lager','chiara'),(67,'Osanna','Birra di frumento ispirata alla tradizione bavarese, prodotta con una significativa percentuale di frumento maltato. Al naso emergono note di banana matura, chiodi di garofano, agrumi e lievito fresco. In bocca è vivace, fresca e scorrevole, con corpo medio-leggero e finale pulito e dissetante.','Weissbier fresca e fragrante con note di banana, chiodi di garofano e agrumi. Morbida, dissetante e perfetta per ogni occasione.','Italia','WAR',5.00,'osanna.webp','5-7°C',2.25,'osanna','2026-06-22 10:04:59','2026-06-22 10:04:59',15,'Pesce e frutti di mare, insalate estive, formaggi freschi, cucina leggera, aperitivi e fritture leggere','Weizenbecher (bicchiere da Weissbier)','Acqua, malto d\'orzo, frumento maltato, luppolo, lievito.','Lattina 33','Weissbier','chiara'),(68,'Tutto Fatto','Tutto Fatto è una Double IPA che racchiude tutto ciò che un appassionato di luppolo può desiderare. Il bouquet aromatico è ricchissimo di mango, ananas, frutto della passione, agrumi e leggere note resinose che si sviluppano con intensità fin dal primo istante. Il corpo pieno e vellutato sostiene una luppolatura generosa che accompagna la bevuta fino a un finale lungo, persistente e appagante.','Una bomba di luppolo dal corpo pieno e dal finale persistente.','Italia','WAR',8.00,'tutto-fatto.webp','6-8°C',4.00,'tutto-fatto','2026-06-22 10:04:59','2026-06-22 10:04:59',80,'Costine BBQ, hamburger gourmet','Teku','Acqua, malto d\'orzo, luppolo, lievito','Lattina 33','Double IPA','chiara');
